// MallServiceServer is the server API for MallService service.
// All implementations must embed UnimplementedMallServiceServer
// for forward compatibility.
type MallServiceServer interface {
	// === Bundle 管理 ===
	CreateBundle(context.Context, *CreateBundleRequest) (*CreateBundleResponse, error)
	UpdateBundleMeta(context.Context, *UpdateBundleMetaRequest) (*UpdateBundleResponse, error)
	UpdateBundlePricing(context.Context, *UpdateBundlePricingRequest) (*UpdateBundleResponse, error)
	GetBundle(context.Context, *GetBundleRequest) (*GetBundleResponse, error)
	ListBundles(context.Context, *ListBundlesRequest) (*ListBundlesResponse, error)
	// === Bundle 购买（唯一顶层入口） ===
	CreateBundleOrder(context.Context, *CreateBundleOrderRequest) (*CreateBundleOrderResponse, error)
	GetBundleOrderSummary(context.Context, *GetBundleOrderSummaryRequest) (*GetBundleOrderSummaryResponse, error)
	GetBundleOrderDetail(context.Context, *GetBundleOrderDetailRequest) (*GetBundleOrderDetailResponse, error)
	ListBundleOrders(context.Context, *ListBundleOrdersRequest) (*ListBundleOrdersResponse, error)
	// Sync and re-evaluate pipeline order exemptions.
	SyncPipelineOrderExemptions(context.Context, *SyncPipelineOrderExemptionsRequest) (*SyncPipelineOrderExemptionsResponse, error)
	// Candidate creates a stage order in gmall.
	CreateStageOrder(context.Context, *CreateStageOrderRequest) (*CreateStageOrderResponse, error)
	// Candidate selects stage exemptions in gmall.
	SelectStageExemptions(context.Context, *SelectStageExemptionsRequest) (*SelectStageExemptionsResponse, error)
	// Candidate creates a course retake order in gmall.
	CreateCourseRetakeOrder(context.Context, *CreateCourseRetakeOrderRequest) (*CreateCourseRetakeOrderResponse, error)
	// Query a pipeline order by its logical order ULID.
	GetPipelineOrderStatus(context.Context, *GetPipelineOrderStatusRequest) (*GetPipelineOrderStatusResponse, error)
	// Query a stage order by its logical order ULID.
	GetStageOrderStatus(context.Context, *GetStageOrderStatusRequest) (*GetStageOrderStatusResponse, error)
	// Query a course retake order by its logical order ULID.
	GetCourseRetakeOrderStatus(context.Context, *GetCourseRetakeOrderStatusRequest) (*GetCourseRetakeOrderStatusResponse, error)
	// Query whether a stage candidate action is already completed.
	GetStageCandidateActionStatus(context.Context, *GetStageCandidateActionStatusRequest) (*GetStageCandidateActionStatusResponse, error)
	// Query whether a course-unit retake payment is already completed.
	GetCourseUnitRetakePaymentStatus(context.Context, *GetCourseUnitRetakePaymentStatusRequest) (*GetCourseUnitRetakePaymentStatusResponse, error)
	// Admin ignores a failed mail task.
	IgnoreMailTask(context.Context, *IgnoreMailTaskRequest) (*IgnoreMailTaskResponse, error)
	// Admin resends a failed mail task.
	ResendMailTask(context.Context, *ResendMailTaskRequest) (*ResendMailTaskResponse, error)
	// Candidate decides to pay for a business order.
	InitiatePayment(context.Context, *InitiatePaymentRequest) (*InitiatePaymentResponse, error)
	// Preview payment details with coupon code calculation.
	PreviewPayment(context.Context, *PreviewPaymentRequest) (*PreviewPaymentResponse, error)
	// --- New Query RPCs ---
	GetOrderSummary(context.Context, *GetOrderSummaryRequest) (*GetOrderSummaryResponse, error)
	GetOrderDetail(context.Context, *GetOrderDetailRequest) (*GetOrderDetailResponse, error)
	ListOrders(context.Context, *ListOrdersRequest) (*ListOrdersResponse, error)
	GetPipelineOrderSummary(context.Context, *GetPipelineOrderSummaryRequest) (*GetPipelineOrderSummaryResponse, error)
	GetPipelineOrderDetail(context.Context, *GetPipelineOrderDetailRequest) (*GetPipelineOrderDetailResponse, error)
	ListPipelineOrders(context.Context, *ListPipelineOrdersRequest) (*ListPipelineOrdersResponse, error)
	GetStageOrderSummary(context.Context, *GetStageOrderSummaryRequest) (*GetStageOrderSummaryResponse, error)
	GetStageOrderDetail(context.Context, *GetStageOrderDetailRequest) (*GetStageOrderDetailResponse, error)
	ListStageOrders(context.Context, *ListStageOrdersRequest) (*ListStageOrdersResponse, error)
	GetCourseRetakeOrderSummary(context.Context, *GetCourseRetakeOrderSummaryRequest) (*GetCourseRetakeOrderSummaryResponse, error)
	GetCourseRetakeOrderDetail(context.Context, *GetCourseRetakeOrderDetailRequest) (*GetCourseRetakeOrderDetailResponse, error)
	ListCourseRetakeOrders(context.Context, *ListCourseRetakeOrdersRequest) (*ListCourseRetakeOrdersResponse, error)
	GetMailTaskSummary(context.Context, *GetMailTaskSummaryRequest) (*GetMailTaskSummaryResponse, error)
	GetMailTaskDetail(context.Context, *GetMailTaskDetailRequest) (*GetMailTaskDetailResponse, error)
	ListMailTasks(context.Context, *ListMailTasksRequest) (*ListMailTasksResponse, error)
	GetNatsMessageSummary(context.Context, *GetNatsMessageSummaryRequest) (*GetNatsMessageSummaryResponse, error)
	GetNatsMessageDetail(context.Context, *GetNatsMessageDetailRequest) (*GetNatsMessageDetailResponse, error)
	ListNatsMessages(context.Context, *ListNatsMessagesRequest) (*ListNatsMessagesResponse, error)
	// Candidate creates a pipeline unlock order.
	CreatePipelineUnlockOrder(context.Context, *CreatePipelineUnlockOrderRequest) (*CreatePipelineUnlockOrderResponse, error)
	GetPipelineUnlockOrderSummary(context.Context, *GetPipelineUnlockOrderSummaryRequest) (*GetPipelineUnlockOrderSummaryResponse, error)
	GetPipelineUnlockOrderDetail(context.Context, *GetPipelineUnlockOrderDetailRequest) (*GetPipelineUnlockOrderDetailResponse, error)
	ListPipelineUnlockOrders(context.Context, *ListPipelineUnlockOrdersRequest) (*ListPipelineUnlockOrdersResponse, error)
	// Candidate creates a credential application order.
	CreateCredentialApplicationOrder(context.Context, *CreateCredentialApplicationOrderRequest) (*CreateCredentialApplicationOrderResponse, error)
	GetCredentialApplicationOrderSummary(context.Context, *GetCredentialApplicationOrderSummaryRequest) (*GetCredentialApplicationOrderSummaryResponse, error)
	GetCredentialApplicationOrderDetail(context.Context, *GetCredentialApplicationOrderDetailRequest) (*GetCredentialApplicationOrderDetailResponse, error)
	ListCredentialApplicationOrders(context.Context, *ListCredentialApplicationOrdersRequest) (*ListCredentialApplicationOrdersResponse, error)
	// Candidate checks whether they are eligible to purchase a pipeline.
	// Returns ALL blockers at once, not just the first one encountered.
	CheckPipelineEligibility(context.Context, *CheckPipelineEligibilityRequest) (*CheckPipelineEligibilityResponse, error)
	AdminPurgeCandidateBundle(context.Context, *AdminPurgeCandidateBundleRequest) (*AdminPurgeCandidateBundleResponse, error)
	CreateBundleUploadURL(context.Context, *CreateBundleUploadURLRequest) (*CreateBundleUploadURLResponse, error)
	GetBundleThumbnailURL(context.Context, *GetBundleThumbnailURLRequest) (*GetBundleThumbnailURLResponse, error)
	mustEmbedUnimplementedMallServiceServer()
}

